/**
 * Category Knowledge Page — Manage category tags and competitor templates.
 *
 * Features:
 * - MUI Tabs: 人群标签 / 购买障碍 / 场景标签 / 卖点标签 / 竞品品牌
 * - Each tab: Chip list + Add button + inline text input
 * - Data stored in DexieDB categories table
 * - Stats bar showing tag counts per category
 */

import React, { useState, useEffect, useCallback } from 'react';
import {
  Box,
  Typography,
  Tabs,
  Tab,
  Chip,
  TextField,
  IconButton,
  Button,
  Card,
  CardContent,
  Grid,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import DeleteIcon from '@mui/icons-material/Delete';
import CategoryIcon from '@mui/icons-material/Category';
import { nanoid } from 'nanoid';
import { db } from '@/shared/db/db';
import { useBrandStore } from '@/shared/stores/brandStore';
import type { Category } from '@/shared/types/category';

/** Tab definitions */
const TABS: { value: string; label: string; key: keyof Category['tags'] }[] = [
  { value: 'audience', label: '人群标签', key: 'audience' },
  { value: 'barriers', label: '购买障碍', key: 'barriers' },
  { value: 'scenes', label: '场景标签', key: 'scenes' },
  { value: 'sellingPoints', label: '卖点标签', key: 'sellingPoints' },
];

/** Tag category card */
interface TagSectionProps {
  title: string;
  tags: string[];
  onAdd: (tag: string) => void;
  onDelete: (tag: string) => void;
}

const TagSection: React.FC<TagSectionProps> = ({ title, tags, onAdd, onDelete }) => {
  const [adding, setAdding] = useState(false);
  const [newTag, setNewTag] = useState('');

  const handleAdd = () => {
    if (newTag.trim()) {
      onAdd(newTag.trim());
      setNewTag('');
      setAdding(false);
    }
  };

  return (
    <Box>
      {/* Add button */}
      <Box sx={{ mb: 1.5, display: 'flex', alignItems: 'center', gap: 1 }}>
        {!adding ? (
          <Button
            size="small"
            variant="outlined"
            startIcon={<AddIcon />}
            onClick={() => setAdding(true)}
          >
            添加标签
          </Button>
        ) : (
          <>
            <TextField
              size="small"
              placeholder="输入新标签..."
              value={newTag}
              onChange={(e) => setNewTag(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleAdd();
                if (e.key === 'Escape') setAdding(false);
              }}
              autoFocus
              sx={{ flex: 1 }}
            />
            <Button size="small" variant="contained" onClick={handleAdd} disabled={!newTag.trim()}>
              添加
            </Button>
            <Button size="small" variant="text" onClick={() => setAdding(false)}>
              取消
            </Button>
          </>
        )}
      </Box>

      {/* Tag chips */}
      <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
        {tags.length === 0 ? (
          <Typography variant="body2" color="text.disabled">
            暂无标签，点击"添加标签"开始
          </Typography>
        ) : (
          tags.map((tag) => (
            <Chip
              key={tag}
              label={tag}
              size="small"
              onDelete={() => onDelete(tag)}
              deleteIcon={<DeleteIcon fontSize="small" />}
              sx={{ fontSize: 12 }}
            />
          ))
        )}
      </Box>
    </Box>
  );
};

const CategoryKnowledgePage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const [tab, setTab] = useState(0);
  const [category, setCategory] = useState<Category | null>(null);
  const [loading, setLoading] = useState(true);

  const brandId = currentBrandId ?? '';

  // Load or create category
  useEffect(() => {
    if (!brandId) {
      setLoading(false);
      return;
    }

    const loadCategory = async () => {
      setLoading(true);
      try {
        const all = await db.categories.toArray();
        let cat = all.find((c) => c.name === brandId) ?? null;

        if (!cat) {
          cat = {
            id: `cat_${nanoid()}`,
            name: brandId,
            tags: {
              audience: [],
              barriers: [],
              scenes: [],
              sellingPoints: [],
            },
            competitorTemplates: [],
          };
          await db.categories.put(cat);
        }

        setCategory(cat);
      } catch (e) {
        console.error('Failed to load category:', e);
      } finally {
        setLoading(false);
      }
    };

    loadCategory();
  }, [brandId]);

  // Save category
  const saveCategory = useCallback(async (updated: Category) => {
    setCategory(updated);
    try {
      await db.categories.put(updated);
    } catch (e) {
      console.error('Failed to save category:', e);
    }
  }, []);

  // Add tag
  const handleAddTag = (key: keyof Category['tags'], tag: string) => {
    if (!category) return;
    if (category.tags[key].includes(tag)) return;
    const updated = {
      ...category,
      tags: {
        ...category.tags,
        [key]: [...category.tags[key], tag],
      },
    };
    saveCategory(updated);
  };

  // Delete tag
  const handleDeleteTag = (key: keyof Category['tags'], tag: string) => {
    if (!category) return;
    const updated = {
      ...category,
      tags: {
        ...category.tags,
        [key]: category.tags[key].filter((t) => t !== tag),
      },
    };
    saveCategory(updated);
  };

  if (!brandId) {
    return (
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
        <Box sx={{ textAlign: 'center' }}>
          <CategoryIcon sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
          <Typography variant="h6" color="text.secondary">
            请先选择品牌
          </Typography>
        </Box>
      </Box>
    );
  }

  if (loading) {
    return (
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
        <Typography variant="body2" color="text.secondary">
          加载中...
        </Typography>
      </Box>
    );
  }

  const currentKey = TABS[tab]?.key ?? 'audience';
  const currentTags = category?.tags[currentKey] ?? [];

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Header */}
      <Box
        sx={{
          p: 2,
          borderBottom: '1px solid',
          borderColor: 'divider',
        }}
      >
        <Typography variant="h6" fontWeight={700} gutterBottom>
          📦 品类知识库
        </Typography>

        {/* Stats bar */}
        {category && (
          <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap', mt: 1 }}>
            {TABS.map((t) => (
              <Chip
                key={t.value}
                label={`${t.label}: ${category.tags[t.key].length}`}
                size="small"
                variant="outlined"
                sx={{ fontSize: 11 }}
              />
            ))}
            <Chip
              label={`竞品模板: ${category.competitorTemplates.length}`}
              size="small"
              variant="outlined"
              sx={{ fontSize: 11 }}
            />
          </Box>
        )}
      </Box>

      {/* Tabs */}
      <Tabs
        value={tab}
        onChange={(_, v) => setTab(v)}
        sx={{ borderBottom: '1px solid', borderColor: 'divider', px: 2 }}
      >
        {TABS.map((t) => (
          <Tab
            key={t.value}
            label={
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                <span>{t.label}</span>
                <Chip
                  label={category?.tags[t.key].length ?? 0}
                  size="small"
                  sx={{ height: 18, fontSize: 10 }}
                />
              </Box>
            }
            sx={{ minHeight: 40, py: 0.5 }}
          />
        ))}
      </Tabs>

      {/* Content */}
      <Box sx={{ flex: 1, overflow: 'auto', p: 3 }}>
        <Card>
          <CardContent>
            <Typography variant="subtitle1" fontWeight={600} gutterBottom>
              {TABS[tab]?.label ?? '标签'}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              {tab === 0 && '定义目标消费人群的特征标签，用于精准定向'}
              {tab === 1 && '记录消费者常见的购买顾虑和障碍因素'}
              {tab === 2 && '定义产品使用场景标签，帮助AI理解用户使用上下文'}
              {tab === 3 && '记录产品核心卖点标签，用于内容策略生成'}
            </Typography>
            <TagSection
              title={TABS[tab]?.label ?? ''}
              tags={currentTags}
              onAdd={(tag) => handleAddTag(currentKey, tag)}
              onDelete={(tag) => handleDeleteTag(currentKey, tag)}
            />
          </CardContent>
        </Card>
      </Box>
    </Box>
  );
};

export default CategoryKnowledgePage;
